import React, { useState } from "react";
import EditorialFlow from "./EditorialFlow";

interface MediaLibraryProps {
  onBack?: () => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ onBack }) => {
  const [view, setView] = useState<'library' | 'flow'>('library');

  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* Bouton Retour */}
      {onBack && (
        <button
          onClick={onBack}
          className="mb-4 px-4 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 rounded-lg text-sm transition-all duration-200 flex items-center gap-2 w-fit"
        >
          <i className="fas fa-arrow-left"></i>
          Retour aux Documents
        </button>
      )}

      {/* En-tête avec Stats */}
      <div className="bg-gradient-to-r from-purple-600 to-indigo-600 rounded-xl shadow-lg mb-4 p-6 text-white">
        <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-3">
              <i className="fas fa-folder-open"></i>
              Médiathèque BCM-GEST
            </h1>
            <p className="text-purple-100 mt-2">
              Gérez vos fichiers bruts, transcriptions, projets et relectures
            </p>
          </div>
          
          {/* Stats Rapides */}
          <div className="flex gap-4 flex-wrap">
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">12</p>
              <p className="text-xs text-purple-100">Fichiers bruts</p>
            </div>
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">5</p>
              <p className="text-xs text-purple-100">Transcriptions</p>
            </div>
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">2</p>
              <p className="text-xs text-purple-100">Projets</p>
            </div>
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">4</p>
              <p className="text-xs text-purple-100">Relectures</p>
            </div>
          </div>
        </div>
      </div>

      {/* Toggle Vue */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-4 p-2">
        <div className="flex gap-2">
          <button
            onClick={() => setView('library')}
            className={`flex-1 px-4 py-3 rounded-lg text-sm font-medium transition-all duration-200 flex items-center justify-center gap-2 ${
              view === 'library'
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
            }`}
          >
            <i className="fas fa-th-large"></i>
            Médiathèque
          </button>
          <button
            onClick={() => setView('flow')}
            className={`flex-1 px-4 py-3 rounded-lg text-sm font-medium transition-all duration-200 flex items-center justify-center gap-2 ${
              view === 'flow'
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
            }`}
          >
            <i className="fas fa-project-diagram"></i>
            Flux Éditorial
          </button>
        </div>
      </div>

      {/* Contenu */}
      {view === 'library' ? (
        <MediaLibraryGrid />
      ) : (
        <EditorialFlow />
      )}
    </div>
  );
};

// ✅ COMPOSANT GRILLE AMÉLIORÉ
const MediaLibraryGrid: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState("Tous");
  const [dateFilter, setDateFilter] = useState("Tous");
  const [statusFilter, setStatusFilter] = useState("Tous");
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  const demoFiles = [
    { id: 1, name: "audio_001.mp3", type: "audio", date: "2025-01-15", size: "5.2 MB", status: "importé" },
    { id: 2, name: "audio_002.mp3", type: "audio", date: "2025-01-15", size: "3.8 MB", status: "transcrit" },
    { id: 3, name: "scan_chapitre1.pdf", type: "pdf", date: "2025-01-14", size: "2.1 MB", status: "importé" },
    { id: 4, name: "photo_001.jpg", type: "image", date: "2025-01-14", size: "1.5 MB", status: "importé" },
    { id: 5, name: "interview_003.mp3", type: "audio", date: "2025-01-13", size: "8.4 MB", status: "transcrit" },
    { id: 6, name: "document_002.pdf", type: "pdf", date: "2025-01-13", size: "4.2 MB", status: "projet livre" },
  ];

  const filteredFiles = demoFiles.filter((file) => {
    const matchesSearch = file.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = typeFilter === "Tous" || file.type === typeFilter;
    const matchesStatus = statusFilter === "Tous" || file.status === statusFilter;
    return matchesSearch && matchesType && matchesStatus;
  });

  const getFileIcon = (type: string) => {
    switch (type) {
      case 'audio': return 'fas fa-music text-blue-500';
      case 'pdf': return 'fas fa-file-pdf text-red-500';
      case 'image': return 'fas fa-file-image text-green-500';
      default: return 'fas fa-file text-gray-500';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'importé': return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-200';
      case 'transcrit': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-200';
      case 'projet livre': return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-200';
      case 'relecture 1': return 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-200';
      case 'relecture 2': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-200';
      default: return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-200';
    }
  };

  return (
    <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
      {/* Barre d'outils améliorée */}
      <div className="bg-gradient-to-r from-gray-50 to-gray-100 dark:from-gray-700/50 dark:to-gray-700 px-6 py-4 border-b border-gray-200 dark:border-gray-700">
        <div className="flex flex-col lg:flex-row gap-4">
          {/* Recherche avec icône */}
          <div className="flex-1 relative">
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 text-base border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent dark:bg-gray-700 dark:text-white transition-all duration-200"
              placeholder="🔍 Rechercher un fichier par nom..."
            />
            <i className="fas fa-search absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
            {searchTerm && (
              <button
                onClick={() => setSearchTerm("")}
                className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                <i className="fas fa-times"></i>
              </button>
            )}
          </div>
          
          {/* Filtres */}
          <div className="flex gap-3 flex-wrap items-center">
            <select
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
              className="px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white transition-all duration-200"
            >
              <option value="Tous">📁 Tous types</option>
              <option value="audio">🎵 Audio</option>
              <option value="pdf">📄 PDF</option>
              <option value="image">🖼️ Image</option>
            </select>
            
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white transition-all duration-200"
            >
              <option value="Tous">📊 Tous statuts</option>
              <option value="importé">📥 Importé</option>
              <option value="transcrit">✍️ Transcrit</option>
              <option value="projet livre">📖 Projet livre</option>
              <option value="relecture 1">👁️ Relecture 1</option>
              <option value="relecture 2">👁️ Relecture 2</option>
            </select>
            
            <select
              value={dateFilter}
              onChange={(e) => setDateFilter(e.target.value)}
              className="px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white transition-all duration-200"
            >
              <option value="Tous">📅 Toutes dates</option>
              <option value="today">Aujourd'hui</option>
              <option value="week">Cette semaine</option>
              <option value="month">Ce mois</option>
            </select>

            {/* Toggle Grid/List */}
            <div className="flex border border-gray-300 dark:border-gray-600 rounded-xl overflow-hidden">
              <button
                onClick={() => setViewMode('grid')}
                className={`px-3 py-3 transition-all duration-200 ${
                  viewMode === 'grid'
                    ? 'bg-purple-600 text-white'
                    : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                }`}
              >
                <i className="fas fa-th"></i>
              </button>
              <button
                onClick={() => setViewMode('list')}
                className={`px-3 py-3 transition-all duration-200 ${
                  viewMode === 'list'
                    ? 'bg-purple-600 text-white'
                    : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                }`}
              >
                <i className="fas fa-list"></i>
              </button>
            </div>
            
            <button className="px-6 py-3 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white rounded-xl transition-all duration-200 flex items-center gap-2 shadow-lg hover:shadow-xl transform hover:-translate-y-0.5">
              <i className="fas fa-upload"></i>
              Importer
            </button>
          </div>
        </div>
        
        {/* Résultats */}
        <div className="mt-4 flex items-center justify-between">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            <strong className="text-purple-600 dark:text-purple-400">{filteredFiles.length}</strong> fichier{filteredFiles.length > 1 ? 's' : ''} trouvé{filteredFiles.length > 1 ? 's' : ''} sur <strong>{demoFiles.length}</strong>
          </p>
          {(searchTerm || typeFilter !== "Tous" || dateFilter !== "Tous" || statusFilter !== "Tous") && (
            <button
              onClick={() => {
                setSearchTerm("");
                setTypeFilter("Tous");
                setDateFilter("Tous");
                setStatusFilter("Tous");
              }}
              className="text-sm text-purple-600 dark:text-purple-400 hover:text-purple-800 dark:hover:text-purple-300 flex items-center gap-1"
            >
              <i className="fas fa-times-circle"></i>
              Réinitialiser les filtres
            </button>
          )}
        </div>
      </div>

      {/* Grille/Liste de fichiers */}
      <div className="p-6 overflow-y-auto" style={{ maxHeight: 'calc(100vh - 450px)' }}>
        {filteredFiles.length === 0 ? (
          <div className="text-center py-16">
            <div className="inline-block p-6 bg-gray-100 dark:bg-gray-700 rounded-full mb-4">
              <i className="fas fa-search text-5xl text-gray-400"></i>
            </div>
            <p className="text-lg text-gray-600 dark:text-gray-400 font-medium mb-2">
              Aucun fichier ne correspond aux filtres
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-500">
              Essayez de modifier vos critères de recherche
            </p>
          </div>
        ) : viewMode === 'grid' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filteredFiles.map((file) => (
              <FileCard key={file.id} file={file} getFileIcon={getFileIcon} getStatusColor={getStatusColor} />
            ))}
          </div>
        ) : (
          <div className="space-y-2">
            {filteredFiles.map((file) => (
              <FileListItem key={file.id} file={file} getFileIcon={getFileIcon} getStatusColor={getStatusColor} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// ✅ COMPOSANT CARTE FICHIER
const FileCard: React.FC<{ file: any; getFileIcon: any; getStatusColor: any }> = ({ file, getFileIcon, getStatusColor }) => {
  return (
